using System.Collections;
using UnityEngine;

[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class DashAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private bool enabledForForm;

    private float dashSpeed;
    private float dashDuration;
    private float dashCooldown;
    private float dashGravityScale;

    private float cooldownTimer;
    private float gravityBeforeDash;

    private Coroutine dashRoutine;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.canDash;

        if (!enabledForForm)
        {
            StopDashIfRunning();
            return;
        }

        dashSpeed = form.dashSpeed;
        dashDuration = form.dashDuration;
        dashCooldown = form.dashCooldown;
        dashGravityScale = form.dashGravityScale;
    }

    // Chamado pelo AbilityRouter quando o bot�o de habilidade for pressionado
    public void TryDash()
    {
        if (!enabledForForm) return;
        if (cooldownTimer > 0f) return;
        if (motor.MovementLocked) return;

        if (dashRoutine != null) StopCoroutine(dashRoutine);
        dashRoutine = StartCoroutine(DashRoutine());
    }

    private IEnumerator DashRoutine()
    {
        cooldownTimer = dashCooldown;
        gravityBeforeDash = rb.gravityScale;

        motor.SetMovementLocked(true, this);
        motor.SetDashing(true);
        rb.gravityScale = dashGravityScale;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;

        float elapsed = 0f;
        while (elapsed < dashDuration)
        {
            rb.velocity = new Vector2(dir * dashSpeed, rb.velocity.y);
            elapsed += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        EndDash();
    }

    private void EndDash()
    {
        rb.gravityScale = gravityBeforeDash;
        motor.SetDashing(false);
        motor.SetMovementLocked(false, this);
        dashRoutine = null;
    }

    private void StopDashIfRunning()
    {
        if (dashRoutine == null) return;

        StopCoroutine(dashRoutine);
        EndDash();
    }

    // ---- IAbility (item 8) ----
    void IAbility.Activate() => TryDash();
    void IAbility.Release() { } // dash não tem "soltar"
    public void Cancel(AbilityCancelReason reason) => StopDashIfRunning();
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => dashRoutine != null;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    public float CooldownDuration => dashCooldown;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && dashRoutine == null && !motor.MovementLocked;

    /// <summary>AnimalsDebugPanel — zera o cooldown do dash.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
